INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", "春咲 ひより", 1.4, 1, 0, 1, 0, 1001, "お！\nあそこに困ってそうな人発見！", 0, 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "みんなみたいに\nわたしも強くならなきゃ", "草野 優衣", 1.4, 1, 0, 1, 0, 1002, "大切な人を\n守れるようになりたい…って", 0, 0, "わ、わたし、\nなに言ってるんだろ\nあはは…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "フェンシングを始めてみては？", "士条 怜", 1.4, 1, 0, 1, 0, 1003, "キミに必要な集中力と感性が", 0, 0, "少しは磨かれると思いますよ。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ねぇ、にいちゃん！", "穂高 みそぎ", 1.5, 1, 0, 1, 0, 1004, "今日はなにして遊ぶ？", 0, 0, "みそぎはねぇ、\nかくれんぼやりたい！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "風宮あかりです", "風宮 あかり", 1.4, 1, 0, 1, 0, 1006, "ねぇ…", 0, 0, "私といっしょに…\nいかない？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "出雲宮子なのー", "出雲 宮子", 1.5, 1, 0, 1, 0, 1007, "プリンたべたいのー", 0, 0, "食べ物の恨みは怖いのー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ボクは虹村雪。", "虹村 雪", 1.4, 1, 0, 1, 0, 1008, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, 0, "いいよ。\n見られることは運命さ…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "フッ…聞いて後悔するがいい！", "柊杏奈", 1.4, 1, 0, 1, 0, 1009, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, 0, "人呼んで「疾風の冥姫」!!");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "マホマホ王国のプリンセス、\nまほ姫どす", "姫宮 真歩", 1.5, 1, 0, 1, 0, 1010, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, 0, "ほんまおおきにやわ～♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "衣之咲璃乃です！", "衣之咲 璃乃", 1.4, 1, 0, 1, 0, 1011, "生き別れたお兄ちゃんを探して\n三千世界！", 0, 0, "ここで会ったが\n100年目～！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", "柏崎 初音", 1.4, 1, 0, 1, 0, 1012, "ち、超能力って…\n何のことかな～？", 0, 0, "…って、お願い！\n誰にも言わないでおいて～！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ちょす！\n美波鈴奈だよ～♪", "美波 鈴奈", 1.4, 1, 0, 1, 0, 1016, "一応カリスマ読モJKやってまっす！", 0, 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "はいたーい。\n喜屋武香織さー。", "喜屋武 香織", 1.4, 1, 0, 1, 0, 1017, "東京は遊園地みたいなところさー", 0, 0, "でも、沖縄もとってもいいとこさー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "支倉伊緒です。", "支倉 伊緒", 1.4, 1, 0, 1, 0, 1018, "先生って呼ばれるのは\nくすぐったいから", 0, 0, "イオちゃんって呼んでね。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", "茜 ミミ", 1.5, 1, 0, 1, 0, 1020, "あ！/\お兄ちゃ～ん\nまってよ～", 0, 0, "ミミをおいてかないでぇ～");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", "栗林 くるみ", 1.5, 1, 0, 1, 0, 1021, "あの……\nふぇ……", 0, 0, "ふぇぇぇぇぇん……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "風宮よりです。\nあああああ！", "風宮 より", 1.4, 1, 0, 1, 0, 1022, "こんな私に貴重な時間を\n割いていただき、", 0, 0, "なんてありがとうございます！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", "北条 綾音", 1.5, 1, 0, 1, 0, 1023, "おにいちゃんどこいくの？\nえ？", 0, 0, "私こっち行きたいー\nね、早く早くー");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "わっ…わっ…私、\n天野すずめといいます！", "天野 すずめ", 1.4, 1, 0, 1, 0, 1025, "ふ、不束者ですが\nどうぞ末永く…って、", 0, 0, "これて何か違う…\nあああすみません！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "……クスクス…私は\n…倉石恵理子……", "倉石 恵理子", 1.4, 1, 0, 1, 0, 1027, "あなたは…運命の……\n伴侶……", 0, 0, "離しませんわ………\n絶対に…!!");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", "佐々木 咲恋", 1.4, 1, 0, 1, 0, 1028, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, 0, "…そうでしょ？？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "桜井望だよ！\nよろしくねっ", "桜井 望", 1.4, 1, 0, 1, 0, 1029, "ぇっと…\nキミ、私のこと知らないの?!", 0, 0, "あはは、\n私もまだまだだなぁ～");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "デケデケデンっ！", "ニノン・ジュベール", 1.4, 1, 0, 1, 0, 1030, "初めまして、\n私はニノン・ジュベール申すデス！", 0, 0, "ショーグン、\nワタシと一緒に天下統一デース！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "上喜しのぶです。\n手元のドクロが父です。", "上喜 しのぶ", 1.4, 1, 0, 1, 0, 1031, "でもって私の隣にいるのが……\nえ、見えない？", 0, 0, "おかしいですね……");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "目指すはビッグな\nお笑い芸人だっぺ！", "野戸まひる", 1.5, 1, 0, 1, 0, 1033, "けんども\nそれには足りないモンが…", 0, 0, "そう、\nオラのボケに突っ込める相方が…！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", "綾瀬 ゆかり", 1.4, 1, 0, 1, 0, 1034, "ちょっと緊張しちゃって…", 0, 0, "ちょ\nちょっと一杯飲んできます…！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "氷川鏡華…です", "氷川 鏡華", 1.5, 1, 0, 1, 0, 1036, "知らない人とは話しちゃいけないので", 0, 0, "これ以上お話しすることは…\nないです！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "柏崎…栞です。", "柏崎 栞", 1.4, 1, 0, 1, 0, 1038, "……あ、アラーム。", 0, 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "ふ、双葉碧です。", "双葉 碧", 1.4, 1, 0, 1, 0, 1040, "私、一人も友達がいなくて……", 0, 0, "野に咲く花が、\n唯一の話相手です。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "三角千歌です。", "三角 千歌", 1.4, 1, 0, 1, 0, 1042, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, 0, "そう思っています。");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "安芸真琴だ。", "安芸 真琴", 1.4, 1, 0, 1, 0, 1043, "あぁ？\nお前のそいつの仲間か？", 0, 0, "う、疑ってすまなかったな…");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "わらわこそは夜を総べる者！", "イリヤ・オーンスタイン", 1.4, 1, 0, 1, 0, 1044, "生けとし生ける全ての者よ！", 0, 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "そこで騎士は妖精を乱暴に……", "遠見 空花", 1.4, 1, 0, 1, 0, 1045, "ぐふふふふ……はっ！", 0, 0, "ｌク、クウカに何かご用ですか!?");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", "宮坂たまき", 1.4, 1, 0, 1, 0, 1046, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, 0, "う～ん…\n猫ってホントに最高にゃ～♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "大神美冬よ！", "大神 美冬", 1.4, 1, 0, 1, 0, 1048, "それでは早速クエストに…", 0, 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "星野静流だよ！", "星野静流", 1.4, 1, 0, 1, 0, 1049, "クエストもバトルも\n掃除も洗濯も", 0, 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "アタシは玉泉美咲。", "玉泉美咲", 1.5, 1, 0, 1, 0, 1050, "見ての通りの\nセクシー美少女で", 0, 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "？？？", "リマ", 1.4, 1, 0, 1, 0, 1052, "？？？？", 0, 0, "？？？？");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "モニカ・ヴァイスヴィントだ。", "モニカ・ヴァイスヴィント", 1.5, 1, 0, 1, 0, 1053, "菓子でつろうなどと\n稚拙な策を……", 0, 0, "そ、そこまでいうなら\nもらってやる");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "モニカ・ヴァイスヴィントだ。", "ペコリーヌ", 1.5, 1, 0, 1, 0, 1058, "菓子でつろうなどと\n稚拙な策を……", 0, 0, "そ、そこまでいうなら\nもらってやる");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "モニカ・ヴァイスヴィントだ。", "コッコロ", 1.5, 1, 0, 1, 0, 1059, "菓子でつろうなどと\n稚拙な策を……", 0, 0, "そ、そこまでいうなら\nもらってやる");
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (2, 1, 0, "モニカ・ヴァイスヴィントだ。", "キャル", 1.5, 1, 0, 1, 0, 1060, "菓子でつろうなどと\n稚拙な策を……", 0, 0, "そ、そこまでいうなら\nもらってやる");
